#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m,s[N],sum[N],sums[N],cnt[N],tot;
long long ans;

int cal(int x,int y){
    if(x>y)
        swap(x,y);
    return sum[y-1]-sum[x-1]-2*(sums[y-2]-sums[x-1]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++){
        scanf("%d",&s[i]);
        sum[i]=sum[i-1]+s[i];
        sums[i]=(i<3?s[i]:sums[i-2]+s[i]);
    }
    for(int i=1,a=0,b;i<=m;i++){
        int last=a;
        scanf("%d%d",&a,&b);
        cnt[a]+=b,tot+=(a%2?b:-b);
        /*if(last){
            if((a-last)%2==0){
                printf("Impossible");
                return 0;
            }
            ans+=cal(a,last);
        }*/
    }
    if(tot){
        printf("Impossible");
        return 0;
    }
    for(int i=1,j=2;i<=n;i+=2){
        if(!cnt[i])
            continue;
        while(!cnt[j] && j<=n)
            j+=2;
        while(cnt[i]){
            ans+=1LL*min(cnt[i],cnt[j])*cal(i,j);
            if(cnt[i]<=cnt[j])
                cnt[j]-=cnt[i],cnt[i]=0;
            else
                cnt[i]-=cnt[j],cnt[j]=0,j+=2;
        }
    }
    printf("%lld",ans);
    return 0;
}
